// ---- Project: App Design and Planning ----

// ---- Product requirements ----
/*
App Name: TaskMaster
Description: A productivity app for managing tasks and projects
Target Users: Students, professionals
Platform: Android

Key Features:
- Create, edit, delete tasks
- Set priorities and deadlines
- Organize by projects
- Track progress
- Reminders
- Dark mode support
*/

// ---- Architecture ----
/*
Clean Architecture:

Presentation Layer:
- Compose UI
- ViewModels
- Navigation

Domain Layer:
- Entities: Task, Project, User
- Use Cases: GetTasks, SaveTask, etc.
- Repository Interfaces

Data Layer:
- Room Database
- DataStore Preferences
- Repository Implementations
*/

// ---- Data models ----
enum class Priority { LOW, MEDIUM, HIGH }

enum class TaskStatus { TODO, IN_PROGRESS, COMPLETED }

data class Task(
    val id: Int = 0,
    val title: String,
    val description: String,
    val projectId: Int? = null,
    val priority: Priority = Priority.MEDIUM,
    val status: TaskStatus = TaskStatus.TODO,
    val dueDate: Long? = null,
    val createdAt: Long = System.currentTimeMillis(),
    val updatedAt: Long = System.currentTimeMillis()
)

data class Project(
    val id: Int = 0,
    val name: String,
    val color: Int,
    val createdAt: Long = System.currentTimeMillis()
)

// ---- Use Cases ----
class GetTasksUseCase(private val repository: TaskRepository) {
    suspend operator fun invoke(): List<Task> = repository.getTasks()
}

class GetTasksByProjectUseCase(private val repository: TaskRepository) {
    suspend operator fun invoke(projectId: Int): List<Task> = repository.getTasksByProject(projectId)
}

class CreateTaskUseCase(private val repository: TaskRepository) {
    suspend operator fun invoke(task: Task): Task = repository.saveTask(task)
}

class UpdateTaskUseCase(private val repository: TaskRepository) {
    suspend operator fun invoke(task: Task): Task = repository.updateTask(task)
}

class DeleteTaskUseCase(private val repository: TaskRepository) {
    suspend operator fun invoke(id: Int) = repository.deleteTask(id)
}

class CompleteTaskUseCase(private val repository: TaskRepository) {
    suspend operator fun invoke(id: Int): Task {
        val task = repository.getTask(id) ?: throw Exception("Task not found")
        val completed = task.copy(status = TaskStatus.COMPLETED)
        return repository.updateTask(completed)
    }
}

// ---- Navigation routes ----
sealed class Screen(val route: String) {
    object TaskList : Screen("tasks")
    object TaskDetail : Screen("task/{taskId}") {
        fun pass(id: Int) = "task/$id"
    }
    object AddTask : Screen("add_task")
    object EditTask : Screen("edit_task/{taskId}") {
        fun pass(id: Int) = "edit_task/$id"
    }
    object Projects : Screen("projects")
    object ProjectDetail : Screen("project/{projectId}") {
        fun pass(id: Int) = "project/$id"
    }
    object Settings : Screen("settings")
}

// ---- Theme ----
@Composable
fun TaskMasterTheme(
    darkTheme: Boolean = isSystemInDarkTheme(),
    content: @Composable () -> Unit
) {
    val colorScheme = if (darkTheme) {
        darkColorScheme(
            primary = Purple80,
            secondary = PurpleGrey80,
            tertiary = Pink80
        )
    } else {
        lightColorScheme(
            primary = Purple40,
            secondary = PurpleGrey40,
            tertiary = Pink40
        )
    }

    MaterialTheme(
        colorScheme = colorScheme,
        typography = Typography,
        content = content
    )
}

